/// <summary>
/// this class will handle form level methods and business logic for form <c>ETGITMEditor</c>
/// </summary>
public final class ETGITMEditorFormHandlerOut
{
    private FormRun thisFormRun;
    private FormDataSource tmpCreatorTable_ds, tmpCreatorLine_ds;
    private ITMTable ITMTable;
    private ITMTmpCreatorTable tmpCreatorTable;
    private ITMTmpCreatorLine tmpCreatorLine;

}

Method.Source:
public static ETGITMEditorFormHandlerOut newFromForm(FormRun _formRun)
{
    ETGITMEditorFormHandlerOut form = new ETGITMEditorFormHandlerOut();

    form.initFromFormRun(_formRun);

    return form;
}

private void initFromFormRun(FormRun _formRun)
{
    thisFormRun = _formRun;

    tmpCreatorTable_ds = thisFormRun.dataHelper().FindDataSource(formDataSourceStr(ITMEditor, ITMTmpCreatorTable));

    tmpCreatorLine_ds = thisFormRun.dataHelper().FindDataSource(formDataSourceStr(ITMEditor, ITMTmpCreatorLine));
}

public ITMTable parmITMTable(ITMTable _itmTable = itmTable)
{
    itmTable = _itmTable;

    return itmTable;
}

public ITMTmpCreatorTable parmTmpCreatorTable(ITMTmpCreatorTable _tmpCreatorTable = tmpCreatorTable)
{
    tmpCreatorTable = _tmpCreatorTable;

    return tmpCreatorTable;
}

public ITMTmpCreatorLine parmTmpCreatorLine(ITMTmpCreatorLine _tmpCreatorLine = tmpCreatorLine)
{
    tmpCreatorLine = _tmpCreatorLine;

    return tmpCreatorLine;
}

private void addBucketContainer()
{
    Args        args = new Args();
    FormRun     addBucketContainer;

    args.parmEnum(FormOpenMode::ForEdit);
    args.parmEnumType(enumNum(FormOpenMode));
    args.name(this.addBucketContainerFormName());
    args.caller(this);

    addBucketContainer = classfactory.formRunClass(args);
    addBucketContainer.init();
    addBucketContainer.run();
    addBucketContainer.wait();
}

public void showBucketContainer(ITMTmpCreatorTable _tmpCreatorTable, ITMTmpCreatorLine _tmpCreatorLine, ITMTable _itmTable)
{
    this.parmITMTable(_itmTable);

    this.parmTmpCreatorTable(_tmpCreatorTable);

    this.parmTmpCreatorLine(_tmpCreatorLine);

    this.addBucketContainer();
}

private FormRun getFormPartByName(str _name)
{
    PartList partList = new PartList(thisFormRun);
    FormRun part;

    for (int i = 1; i <= partList.partCount(); i++)
    {
        part = partList.getPartById(i);

        if (part.name() == _name)
        {
            return part;
        }
    }
    return null;
}

public void runFillTables()
{
    if (thisFormRun && formHasMethod(thisFormRun, identifierStr(fillTables)))
    {
        thisFormRun.fillTables();
    }
}

public void refreshFactBoxReceiptDetails(ITMTmpCreatorTable _tmpCreatorTable)
{
    FormRun factBox = this.getFormPartByName(formStr(ITMShipmentReceiptDetails));

    if (factBox && formHasMethod(factBox, identifierStr(updateReceiptDetails)))
    {
        factBox.args().record(_tmpCreatorTable);
    }
}

public void refreshFactBoxShipmentTotals(ITMTmpCreatorLine _tmpCreatorLine)
{
    FormRun factBox = this.getFormPartByName(formStr(ITMShipmentTotalsPart));

    if (factBox && formHasMethod(factBox, identifierStr(updateTotals)))
    {
        factBox.args().record(_tmpCreatorLine);
    }
}

public boolean isLineExistInBucket(ITMTmpCreatorLine _tmpCreatorLine)
{
    boolean ret;
    ITMTmpCreatorLine tmp;

    tmp.setTmpData(_tmpCreatorLine);

    select firstonly RecId from tmp
        where tmp.AddedToBucket == NoYes::Yes;        

    return (tmp.RecId != 0);
}
